#include <bits/stdc++.h>
using namespace std;
int l,n,k,a[100005],dist[100005];
bool check(int x){
	int sum=k;
	for(int i=1;i<n;i++){
		if(dist[i]<=x)
			continue;
		else if(sum<dist[i]/x+(dist[i]%x>0)-1)
			return false;
		else if(dist[i]/(sum+1)+(dist[i]%(sum+1)>0)>x)
			return false;
		else
			sum-=dist[i]/x+(dist[i]%x>0)-1;
	}
	return true;
}
int main(){
    scanf("%d%d%d",&l,&n,&k);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    sort(a+1,a+n+1);
    int left=1,right=0;
    for(int i=1;i<n;i++)
    	dist[i]=a[i+1]-a[i],right=max(right,dist[i]);
    while(left<right){
    	int mid=(left+right)/2;
    	if(check(mid))
    		right=mid;
    	else
    		left=mid+1;
	}
	printf("%d",left);
    return 0;
}
